INSERT INTO jobs (id, company_id, title, description, location, salary_range, status, priority, urgency_notes, employment_type, pay_type) VALUES
  ('j0000000-0000-0000-0000-000000000001', 'c0000000-0000-0000-0000-000000000001', 'Commercial HVAC Service Technician', 'Troubleshoot, repair, and maintain commercial HVAC systems across DFW school district contracts. Must have EPA 608 Universal and reliable transportation. Rooftop unit experience required.', 'Dallas, TX', '$55,000 - $72,000', 'open', 'high', 'School starts in August — need someone onboarded by July 15.', 'full_time', 'salary'),
  ('j0000000-0000-0000-0000-000000000002', 'c0000000-0000-0000-0000-000000000002', 'Residential HVAC Installer', 'Install residential HVAC systems including split systems, heat pumps, and ductwork. Experience with Trane and Carrier preferred.', 'Fort Worth, TX', '$22 - $30/hr', 'open', 'medium', NULL, 'full_time', 'hourly'),
  ('j0000000-0000-0000-0000-000000000003', 'c0000000-0000-0000-0000-000000000003', 'Lead HVAC Installer', 'Lead a 3-person crew on high-end residential installs in the Austin area. Must have 7+ years experience and ability to read blueprints.', 'Austin, TX', '$70,000 - $82,000', 'open', 'high', 'Current lead gave 2-week notice. Critical backfill.', 'full_time', 'salary'),
  ('j0000000-0000-0000-0000-000000000004', 'c0000000-0000-0000-0000-000000000004', 'Industrial Refrigeration Technician', 'Service and repair industrial refrigeration systems in food processing and cold storage facilities. Must have EPA 608 Universal and OSHA 30.', 'Houston, TX', '$75,000 - $90,000', 'open', 'medium', NULL, 'full_time', 'salary'),
  ('j0000000-0000-0000-0000-000000000005', 'c0000000-0000-0000-0000-000000000001', 'HVAC Controls Technician', 'Install, program, and troubleshoot DDC building automation systems. Experience with Tridium Niagara or Honeywell preferred.', 'Dallas, TX', '$70,000 - $85,000', 'open', 'high', 'New school district contract starting Q3. Need 2 controls techs.', 'full_time', 'salary'),
  ('j0000000-0000-0000-0000-000000000006', 'c0000000-0000-0000-0000-000000000009', 'Geothermal Install Technician', 'Install geothermal heat pump systems for residential customers. Training provided on proprietary systems. Must have HVAC install background.', 'Frisco, TX', '$60,000 - $75,000', 'open', 'low', NULL, 'full_time', 'salary'),
  ('j0000000-0000-0000-0000-000000000007', 'c0000000-0000-0000-0000-000000000005', 'HVAC Service Tech (Temp-to-Hire)', 'Residential service calls. Company vehicle provided after conversion to full-time. Must have valid driver license.', 'San Antonio, TX', '$20 - $26/hr', 'open', 'medium', NULL, 'temp_to_hire', 'hourly'),
  ('j0000000-0000-0000-0000-000000000008', 'c0000000-0000-0000-0000-000000000002', 'Sheet Metal Duct Fabricator', 'Fabricate and install ductwork for residential and light commercial projects. TIG welding and blueprint reading required.', 'Fort Worth, TX', '$55,000 - $68,000', 'closed', 'low', 'Position filled internally. May reopen if volume increases.', 'full_time', 'salary');
